100	template <class T, class U>
101	T clamp(const U v)
102	{
103	    constexpr T min_t = std::numeric_limits<T>::min();
104	    constexpr T max_t = std::numeric_limits<T>::max();
105	    return (v < min_t) ? min_t : (v > max_t) ? max_t : T(v);
