108	/***********************************************************************
109	 * Convert xx to items32 sc16 buffer
110	 **********************************************************************/
111	template <typename T>
112	UHD_INLINE item32_t xx_to_item32_sc16_x1(
113	    const std::complex<T>& num, const double scale_factor)
114	{
115	    uint16_t real = clamp<int16_t>(num.real() * float(scale_factor));
116	    uint16_t imag = clamp<int16_t>(num.imag() * float(scale_factor));
117	    return (item32_t(real) << 16) | (item32_t(imag) << 0);
118	}
119	
120	template <>
121	UHD_INLINE item32_t xx_to_item32_sc16_x1(const sc16_t& num, const double)
122	{
123	    uint16_t real = int16_t(num.real());
124	    uint16_t imag = int16_t(num.imag());
125	    return (item32_t(real) << 16) | (item32_t(imag) << 0);
126	}
127	
128	template <xtox_t to_wire, typename T>
129	UHD_INLINE void xx_to_item32_sc16(const std::complex<T>* input,
130	    item32_t* output,
131	    const size_t nsamps,
132	    const double scale_factor)
133	{
134	    for (size_t i = 0; i < nsamps; i++) {
135	        const item32_t item = xx_to_item32_sc16_x1(input[i], scale_factor);
136	        output[i]           = to_wire(item);
