140	template <typename T>
141	UHD_FORCE_INLINE sc16_t xx_to_sc16_x1(
142	    const std::complex<T>& num, const double scale_factor)
143	{
144	    uint16_t real = clamp<int16_t>(num.real() * float(scale_factor));
145	    uint16_t imag = clamp<int16_t>(num.imag() * float(scale_factor));
146	    return sc16_t(real, imag);
147	}
148	
149	template <typename T>
150	UHD_FORCE_INLINE void xx_to_chdr_sc16(const std::complex<T>* input,
151	    sc16_t* output,
152	    const size_t nsamps,
153	    const double scale_factor)
154	{
155	    for (size_t i = 0; i < nsamps; i++) {
156	        output[i] = xx_to_sc16_x1(input[i], scale_factor);
157	    }
158	}
159	
160	/***********************************************************************
161	 * Convert items32 sc16 buffer to xx
162	 **********************************************************************/
163	template <typename T>
164	UHD_INLINE std::complex<T> item32_sc16_x1_to_xx(
165	    const item32_t item, const double scale_factor)
166	{
167	    return std::complex<T>(T(int16_t(item >> 16) * float(scale_factor)),
168	        T(int16_t(item >> 0) * float(scale_factor)));
