174	    return sc16_t(int16_t(item >> 16), int16_t(item >> 0));
175	}
176	
177	template <xtox_t to_host, typename T>
178	UHD_INLINE void item32_sc16_to_xx(const item32_t* input,
179	    std::complex<T>* output,
180	    const size_t nsamps,
181	    const double scale_factor)
182	{
183	    for (size_t i = 0; i < nsamps; i++) {
184	        const item32_t item_i = to_host(input[i]);
