188	
189	template <typename T>
190	UHD_FORCE_INLINE std::complex<T> chdr_sc16_x1_to_xx(
191	    const sc16_t item, const double scale_factor)
192	{
193	    return std::complex<T>(
194	        T(item.real()) * T(scale_factor), T(item.imag()) * T(scale_factor));
195	}
196	
197	template <typename T>
198	UHD_FORCE_INLINE void chdr_sc16_to_xx(const sc16_t* input,
199	    std::complex<T>* output,
200	    const size_t nsamps,
201	    const double scale_factor)
202	{
203	    for (size_t i = 0; i < nsamps; i++) {
204	        output[i] = chdr_sc16_x1_to_xx<T>(input[i], scale_factor);
