208	/***********************************************************************
209	 * Convert xx to items32 sc8 buffer
210	 **********************************************************************/
211	template <typename T>
212	UHD_INLINE item32_t xx_to_item32_sc8_x1(
213	    const std::complex<T>& in0, const std::complex<T>& in1, const double scale_factor)
214	{
215	    uint8_t real1 = clamp<int8_t>(in0.real() * float(scale_factor));
216	    uint8_t imag1 = clamp<int8_t>(in0.imag() * float(scale_factor));
217	    uint8_t real0 = clamp<int8_t>(in1.real() * float(scale_factor));
218	    uint8_t imag0 = clamp<int8_t>(in1.imag() * float(scale_factor));
219	    return (item32_t(real0) << 8) | (item32_t(imag0) << 0) | (item32_t(real1) << 24)
220	           | (item32_t(imag1) << 16);
221	}
222	
223	template <>
224	UHD_INLINE item32_t xx_to_item32_sc8_x1(
225	    const sc16_t& in0, const sc16_t& in1, const double)
226	{
227	    uint8_t real1 = clamp<int8_t>(in0.real());
228	    uint8_t imag1 = clamp<int8_t>(in0.imag());
229	    uint8_t real0 = clamp<int8_t>(in1.real());
230	    uint8_t imag0 = clamp<int8_t>(in1.imag());
231	    return (item32_t(real0) << 8) | (item32_t(imag0) << 0) | (item32_t(real1) << 24)
232	           | (item32_t(imag1) << 16);
233	}
234	
235	template <>
236	UHD_INLINE item32_t xx_to_item32_sc8_x1(const sc8_t& in0, const sc8_t& in1, const double)
237	{
238	    uint8_t real1 = int8_t(in0.real());
239	    uint8_t imag1 = int8_t(in0.imag());
240	    uint8_t real0 = int8_t(in1.real());
241	    uint8_t imag0 = int8_t(in1.imag());
242	    return (item32_t(real0) << 8) | (item32_t(imag0) << 0) | (item32_t(real1) << 24)
243	           | (item32_t(imag1) << 16);
244	}
245	
246	template <xtox_t to_wire, typename T>
247	UHD_INLINE void xx_to_item32_sc8(const std::complex<T>* input,
248	    item32_t* output,
249	    const size_t nsamps,
250	    const double scale_factor)
251	{
252	    const size_t num_pairs = nsamps / 2;
253	    for (size_t i = 0, j = 0; i < num_pairs; i++, j += 2) {
254	        const item32_t item = xx_to_item32_sc8_x1(input[j], input[j + 1], scale_factor);
255	        output[i]           = to_wire(item);
256	    }
257	
258	    if (nsamps != num_pairs * 2) {
259	        const item32_t item =
260	            xx_to_item32_sc8_x1(input[nsamps - 1], std::complex<T>(0), scale_factor);
261	        output[num_pairs] = to_wire(item);
262	    }
263	}
264	
265	/***********************************************************************
266	 * Convert items32 sc8 buffer to xx
267	 **********************************************************************/
268	template <typename T>
269	UHD_INLINE void item32_sc8_x1_to_xx(const item32_t item,
270	    std::complex<T>& out0,
271	    std::complex<T>& out1,
272	    const double scale_factor)
273	{
274	    out1 = std::complex<T>(T(int8_t(item >> 8) * float(scale_factor)),
275	        T(int8_t(item >> 0) * float(scale_factor)));
276	    out0 = std::complex<T>(T(int8_t(item >> 24) * float(scale_factor)),
277	        T(int8_t(item >> 16) * float(scale_factor)));
278	}
279	
280	template <>
281	UHD_INLINE void item32_sc8_x1_to_xx(
282	    const item32_t item, sc16_t& out0, sc16_t& out1, const double)
283	{
284	    out1 = sc16_t(int16_t(int8_t(item >> 8)), int16_t(int8_t(item >> 0)));
285	    out0 = sc16_t(int16_t(int8_t(item >> 24)), int16_t(int8_t(item >> 16)));
286	}
287	
288	template <>
289	UHD_INLINE void item32_sc8_x1_to_xx(
290	    const item32_t item, sc8_t& out0, sc8_t& out1, const double)
291	{
292	    out1 = sc8_t(int8_t(int8_t(item >> 8)), int8_t(int8_t(item >> 0)));
293	    out0 = sc8_t(int8_t(int8_t(item >> 24)), int8_t(int8_t(item >> 16)));
294	}
295	
296	template <xtox_t to_host, typename T>
297	UHD_INLINE void item32_sc8_to_xx(const item32_t* input,
298	    std::complex<T>* output,
299	    const size_t nsamps,
300	    const double scale_factor)
301	{
302	    input = reinterpret_cast<const item32_t*>(size_t(input) & ~0x3);
303	    std::complex<T> dummy;
304	    size_t num_samps = nsamps;
305	
306	    if ((size_t(input) & 0x3) != 0) {
307	        const item32_t item0 = to_host(*input++);
308	        item32_sc8_x1_to_xx(item0, dummy, *output++, scale_factor);
309	        num_samps--;
310	    }
311	
312	    const size_t num_pairs = num_samps / 2;
313	    for (size_t i = 0, j = 0; i < num_pairs; i++, j += 2) {
314	        const item32_t item_i = to_host(input[i]);
315	        item32_sc8_x1_to_xx(item_i, output[j], output[j + 1], scale_factor);
316	    }
317	
318	    if (num_samps != num_pairs * 2) {
319	        const item32_t item_n = to_host(input[num_pairs]);
320	        item32_sc8_x1_to_xx(item_n, output[num_samps - 1], dummy, scale_factor);
321	    }
322	}
323	
324	#endif /* INCLUDED_LIBUHD_CONVERT_COMMON_HPP */
