            // aligned
            convert_fc32_1_to_item32_1_bswap_guts(_) break;
        default:
            // we are not 8 or 16-byte aligned, so do fast processing with the unaligned
            // load
            convert_fc32_1_to_item32_1_bswap_guts(u_)
    }

